INSERT INTO `location` (`id`, `slug`, `placename`, `address`, `city`, `country`, `latitude`, `longitude`, `owner_id`, `created_at`, `updated_at`, `main`, `uid`, `store`, `processed_at`, `department`, `region`, `city_district`, `postal_code`, `eve_id`, `agenda_id`, `insee`, `set_uid`, `ext_id`, `deleted`, `duplicates`) VALUES
(761374, 'chateau-de-montrottier_8028_13331_18213', 'Château de Montrottier - Musée Léon Marès', 'Allée du château, Lovagny, Haute-Savoie, Auvergne-Rhône-Alpes', 'Lovagny', 'FR', '45.898752', '6.040199', NULL, '2019-01-22 16:43:02', '2019-02-01 10:19:09', 0, 77635822, '{\"image\":\"location88784803.jpg\",\"description\":{\"fr\":\"C\'est une forteresse pentagonale dont le plan s\'ordonne autour d\'un donjon cylindrique à machicoulis. Les bâtiments les plus anciens remontent au 13ème siècle ; les autres appartiennent au 15ème. Malgré les remaniements, le château de Montrottier conserve aujourd\'hui encore des éléments significatifs de l\'architecture militaire médiévale. Isolée sur le piton rocheux et protégée au nord par la «Grande Fosse» (lit du Fier au quaternaire), la Tour des Religieuses remonte au 13ème siècle et présente certaines caractéristiques architecturales d\'une maison-forte sans en être une à proprement parler. Cette tour est ainsi la partie la plus ancienne du château, château qui prend forme au fil ds siècles. En effet, c\'est au 14ème siècle qu\'est édifiée la tourelle d\'angle abritant l\'escalier hélicoïdal à limon suspendu. Le logis des chevaliers, le logis des comtes, la courtine et le donjon datent du 15ème siècle. Les terrasses et les jardins du 19ème.\",\"it\":\"È un piano di fortezza pentagonale di cui è organizzato intorno a donjon cilindrico a machicoulis. Gli edifici(costruzione) (precedenti) più antichi ritornano fino al 13esimo secolo; gli altri appartengono al 15esimo. Malgrado modifiche, il castello di Montrottier tiene oggi perfino elementi importanti(notevoli) d\'architettura militare medievale. Isolato sul gancio roccioso(malfermo) e protetto nel nord dalla «Fossa Grande (la Tomba)» (il letto del Fiero nel gruppo di quattro), la Torre delle Monache ritorna fino al 13esimo secolo e introduce (presenta) alcun carastéristiques architettonico di un familiare (la casa) - forte(solido) senza essere quel che in modo conveniente parlando. Questa torre è così la parte (precedente) più antica del castello, il castello che assume il volo dal filo ds i secoli. Infatti, è nel 14esimo secolo quando è costruito la torretta d\'angolo che ripara la scala elicoidale con limo pendente. La casa dei cavalieri, la casa dei numeri(conti,capi d\'accusa), la tenda(separio) e la data donjon il 15esimo secolo. Terrazze e giardini del 19esimo.\",\"es\":\"Es una fortaleza pentagonale cuyo plan se ordena alrededor de una torre del homenaje cilíndrica a machicoulis. Los edificios más antiguos suben al siglo 13; otros(as) pertenecen al 15o. A pesar de las revisiones, el castillo de Montrottier todavía conserva hoy elementos significativos de la arquitectura militar medieval. Aislada sobre el pico rocoso y protegida en el norte por el «Gran Hoyo» (cama del Orgulloso al cuaternario), la Torre de las Monjas sube al siglo 13 y presenta algunas carastéristiques arquitectural de una casa - fuerte sin ser una hablando con propiedad. Esta torre es así la parte más antigua del castillo, el castillo que toma forma al hilo ds los siglos. En efecto, es en el siglo 14 cuando es edificada la torrecilla de ángulo que abriega la escalera helicoidal a limo suspendido. La vivienda de los caballeros, la vivienda de los condes, la cortina y la torre del homenaje fechan siglo 15\\\\. Las terrazas y los jardines del 19o.\",\"de\":\"Das ist eine fünfeckige Festung, deren Plan sich um einen zylindrischen Bergfried machicoulis ordnet. Die ältesten Gebäude gehen auf das 13\\\\. Jahrhundert zurück; andere gehören zum 15.. Trotz der Umbildungen behält das Schloss von Montrottier heute noch für die mittelalterliche militärische Architektur bedeutende Elemente. Auf dem felsigen Haken abgeschnitten und im Norden von der \\\"Großen Grube(Grab)\\\" \\\"geschützt\\\" (Bett des Stolzen im Quaternaire), geht der Turm der Nonnen auf das 13\\\\. Jahrhundert zurück und stellt manche die eines Hauses architektonischen carastéristiques vor - stark, ohne ein genau genommen zu sein. Dieser Turm ist der älteste Teil(Seite) vom Schloss, dem Schloss, das Form im Faden ds Jahrhunderte nimmt. Wirklich eben im 14\\\\. Jahrhundert wird das die schraubenförmige Treppe in hängendem Schlamm schützende Ecktürmchen erbaut(belehrt). Die Behausung der Ritter, die Behausung der Grafen, der Vorhang und der Bergfried datieren das 15\\\\. Jahrhundert. Die Terrassen und die Gärten des 19..\",\"en\":\"It is a pentagonal fortress plan of which is organised around a cylindrical donjon to machicoulis. The most old(former) buildings(ships) go back up(raise) to the 13th century; others belong to the 15th. In spite of reorganisations, the castle of Montrottier keeps(preserves) today even significant elements of medieval military architecture. Isolated on the rock peak and protected in the North by the «Big(Great) Pit» (bed of the Proud in the quaternary), the Tower of the Nuns goes back up(raises) to the 13th century and presents some architectural carastéristiques of a house - strong without being one properly speaking. This tower is so the most old(former) part(party) of the castle, castle which takes shape in the thread(wire) ds centuries. Indeed, it is in the 14th century when is built the turret of angle sheltering the helical staircase with hanging silt. The home of the knights, the home of the counts, the curtain and the donjon date the 15th century. Terraces and gardens of the 19th.\"},\"tags\":[{\"id\":40,\"label\":\"Musée de France\"},{\"id\":42,\"label\":\"Monument historique\"},{\"id\":19,\"label\":\"Decorative Arts\"}],\"website\":\"http://www.chateaudemontrottier.com/fr/historique.html\",\"phone\":\"04 50 46 23 02\",\"links\":[],\"access\":{\"fr\":\"10 km d\'Annecy\",\"it\":\"10 chilometri di Annecy\",\"es\":\"10 kms de Annecy\",\"de\":\"10 km von Annecy\",\"en\":\"10 km from Annecy\"},\"state\":1,\"timezone\":\"Europe/Paris\",\"imageCredits\":null,\"extId\":null}', '2016-01-10 00:11:11', 'Haute-Savoie', 'Auvergne-Rhône-Alpes', NULL, '74330', NULL, 30907, '74152', 1903810, NULL, 0, '{\"candidates\":[], \"disqualified\":[]}' ),
